// HasPolicyBindings applies the HasEdge predicate on the "policy_bindings" edge.
func HasPolicyBindings() predicate.Agent {
	return predicate.Agent(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, true, PolicyBindingsTable, PolicyBindingsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPolicyBindingsWith applies the HasEdge predicate on the "policy_bindings" edge with a given conditions (other predicates).
func HasPolicyBindingsWith(preds ...predicate.PolicyBinding) predicate.Agent {
	return predicate.Agent(func(s *sql.Selector) {
		step := newPolicyBindingsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Agent) predicate.Agent {
	return predicate.Agent(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Agent) predicate.Agent {
	return predicate.Agent(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Agent) predicate.Agent {
	return predicate.Agent(sql.NotPredicates(p))
}
